using System;
using System.Linq;
using System.Web.Mvc;
using YourProjectNamespace.Models;
using YourProjectNamespace.Data;

namespace YourProjectNamespace.Controllers
{
    public class ProductController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();

        public ActionResult Reviews(int productId)
        {
            var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }
    }
}

@model IEnumerable<YourProjectNamespace.Models.Review>

@foreach (var review in Model)
{
    <div class="review">
        <div class="review-content">
            @Html.Raw(review.Content) // Render with formatting
        </div>
        <div class="review-author">
            <strong>By: @Html.Encode(review.Author)</strong>
        </div>
        <div class="review-date">
            <em>@review.CreatedDate.ToString("MMMM dd, yyyy")</em>
        </div>
    </div>
}